script:
if not doc.flags.get("hr_notify_sent"):
    doc.flags.hr_notify_sent = True

    user_roles = frappe.db.sql("""
        SELECT role FROM `tabHas Role`
        WHERE parent = %s
    """, frappe.session.user, as_dict=True)

    user_roles = [r.role for r in user_roles]

    if "Employee" in user_roles and "HR Manager" not in user_roles and "HR User" not in user_roles:
        changed_fields = []
        old_doc = doc.get_doc_before_save()

        if old_doc:
            for field in doc.meta.fields:
                fieldname = field.fieldname

                if field.fieldtype == "Table":
                    old_rows = old_doc.get(fieldname) or []
                    new_rows = doc.get(fieldname) or []

                    if len(old_rows) != len(new_rows):
                        changed_fields.append(field.label or fieldname)
                        continue

                    child_meta = frappe.get_meta(field.options)
                    row_changed = False

                    for old_row, new_row in zip(old_rows, new_rows):
                        for child_field in child_meta.fields:
                            cfn = child_field.fieldname
                            if old_row.get(cfn) != new_row.get(cfn):
                                row_changed = True
                                break
                        if row_changed:
                            break

                    if row_changed:
                        changed_fields.append(field.label or fieldname)
                else:
                    if doc.get(fieldname) != old_doc.get(fieldname):
                        changed_fields.append(field.label or fieldname)

        if changed_fields:
            subject_text = doc.employee_name + " updated: " + ", ".join(changed_fields)

            hr_user_rows = frappe.db.sql("""
                SELECT u.name
                FROM `tabUser` u
                JOIN `tabHas Role` hr ON hr.parent = u.name
                WHERE hr.role IN ('HR Manager', 'HR User')
                AND u.enabled = 1
            """, as_dict=True)

            unique_users = list(set([r.name for r in hr_user_rows]))

            for user_email in unique_users:
                frappe.get_doc({
                    "doctype": "Notification Log",
                    "for_user": user_email,
                    "from_user": frappe.session.user,
                    "subject": subject_text,
                    "type": "Alert",
                    "document_type": "Employee",
                    "document_name": doc.name
                }).insert(ignore_permissions=True)
